#include "Renderer.hpp"
Renderer::Renderer(){ fontOk_=font_.loadFromFile("/System/Library/Fonts/SFNS.ttf"); if(!fontOk_)fontOk_=font_.loadFromFile("/System/Library/Fonts/Helvetica.ttc"); }
static sf::Color color(PieceType t){static const sf::Color c[]={sf::Color(52,211,255),sf::Color(255,210,70),sf::Color(190,100,255),sf::Color(70,230,150),sf::Color(255,90,130),sf::Color(75,140,255),sf::Color(255,150,65)};return c[(int)t];}
void Renderer::text(sf::RenderWindow&w,const std::string&s,unsigned size,float x,float y,sf::Color c){if(!fontOk_)return;sf::Text t(s,font_,size);t.setFillColor(c);t.setPosition(x,y);w.draw(t);}
void Renderer::draw(sf::RenderWindow&w,const Game&g){w.clear(sf::Color(10,14,30)); sf::RectangleShape panel({420,700});panel.setPosition(70,40);panel.setFillColor(sf::Color(18,24,48));w.draw(panel); sf::RectangleShape shadow({362,642});shadow.setPosition(99,69);shadow.setFillColor(sf::Color(8,12,25));w.draw(shadow); const float cell=32.f, ox=101,oy=71; for(int y=0;y<Board::Height;++y)for(int x=0;x<Board::Width;++x){sf::RectangleShape q({30,30});q.setPosition(ox+x*cell,oy+y*cell);q.setFillColor(g.board().occupied(x,y)?color(g.board().at(x,y)):sf::Color(20,27,50));w.draw(q);} auto drawShape=[&](Shape s,int px,int py,PieceType t){for(auto c:s){sf::RectangleShape q({30,30});q.setPosition(ox+(px+c.x)*cell,oy+(py+c.y)*cell);q.setFillColor(color(t));w.draw(q);}};if(!g.gameOver())drawShape(g.current(),g.currentX(),g.currentY(),g.currentType()); text(w,"NEON TETRIS",30,540,55,sf::Color(115,225,255));text(w,"SCORE",14,555,170,sf::Color(145,160,190));text(w,std::to_string(g.score()),30,555,193,sf::Color::White);text(w,"LINES",14,555,260,sf::Color(145,160,190));text(w,std::to_string(g.lines()),30,555,283,sf::Color::White);text(w,"LEVEL",14,555,350,sf::Color(145,160,190));text(w,std::to_string(g.level()),30,555,373,sf::Color::White);text(w,"← →  MOVE",15,540,500,sf::Color(190,200,220));text(w,"↑      ROTATE",15,540,530,sf::Color(190,200,220));text(w,"↓      SOFT DROP",15,540,560,sf::Color(190,200,220));text(w,"SPACE  HARD DROP",15,540,590,sf::Color(190,200,220));text(w,"R      RESTART",15,540,620,sf::Color(190,200,220));if(g.gameOver()){sf::RectangleShape over({360,110});over.setPosition(100,330);over.setFillColor(sf::Color(10,14,30,235));w.draw(over);text(w,"GAME OVER",28,185,350,sf::Color(255,105,140));text(w,"PRESS R TO RESTART",14,190,392,sf::Color::White);} }

